mapper.select:
SELECT jp.id, jp.publisher_id, su.username AS publisher_name, jp.category_id, jc.name AS category_name, jp.title, jp.description, jp.location, jp.salary_type, jp.salary_amount, jp.start_time, jp.end_time, jp.recruit_num, jp.hired_num, jp.status, jp.audit_status, jp.create_time FROM job_post jp LEFT JOIN sys_user su ON jp.publisher_id = su.id LEFT JOIN job_category jc ON jp.category_id = jc.id WHERE jp.status = 2 AND jp.deleted = 0
AND (jp.title LIKE CONCAT('%', #{keyword}, '%') OR jp.description LIKE CONCAT('%', #{keyword}, '%'))
AND jp.category_id = #{categoryId}
AND jp.location LIKE CONCAT('%', #{location}, '%')
AND jp.salary_type = #{salaryType}
ORDER BY jp.create_time DESC
